  "designs": [
    {
      "screenId": "8Pz5IkkkCujA",
      "screenName": "Prestige Homepage",
      "html": "<head><style id="theme-vars">
    :root {
        --background: #ffffff;
        --foreground: #111111;
        --primary: #111111;
        --primary-foreground: #ffffff;
        --muted: #f7f7f7;
        --muted-foreground: #666666;
        --border: #e6e6e6;
    }
    * { box-sizing: border-box; }
    body {
        margin: 0;
        background: var(--background);
        color: var(--foreground);
        -webkit-font-smoothing: antialiased;
    }
    a { color: inherit; text-decoration: none; }
    h1, h2, h3, h4, h5 { margin: 0; font-weight: 400; letter-spacing: 0.05em; }
    p { margin: 0; }
</style>

<style id="announcement-styles">
    .announcement {
        background: var(--primary);
        color: var(--primary-foreground);
        text-align: center;
        padding: 12px 20px;
        font-size: 11px;
        letter-spacing: 0.15em;
        text-transform: uppercase;
        font-weight: 500;
    }
</style>

<style id="header-styles">
    .header {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 24px 60px;
        background: var(--background);
        border-bottom: 1px solid var(--border);
    }
    .header-nav {
        display: flex;
        align-items: center;
        gap: 40px;
        flex: 1;
    }
    .header-nav.right {
        justify-content: flex-end;
        gap: 24px;
    }
    .header-link {
        font-size: 13px;
        text-transform: uppercase;
        letter-spacing: 0.1em;
        font-weight: 500;
        cursor: pointer;
    }
    .header-center {
        flex: 0 0 auto;
        display: flex;
        justify-content: center;
    }
    .header-icon {
        width: 20px;
        height: 20px;
        display: flex;
        align-items: center;
        justify-content: center;
        cursor: pointer;
    }
</style>

<style id="hero-styles">
    .hero {
        position: relative;
        width: 100%;
        height: 750px;
        display: flex;
        align-items: center;
        justify-content: center;
    }
    .hero-bg {
        position: absolute;
        top: 0; left: 0; right: 0; bottom: 0;
        z-index: 1;
    }
    .hero-bg img {
        width: 100%;
        height: 100%;
        object-fit: cover;
    }
    .hero-overlay {
        position: absolute;
        top: 0; left: 0; right: 0; bottom: 0;
        background: rgba(0,0,0,0.3);
        z-index: 2;
    }
    .hero-content {
        position: relative;
        z-index: 3;
        text-align: center;
        color: #ffffff;
        display: flex;
        flex-direction: column;
        align-items: center;
        padding: 0 20px;
    }
    .hero-subtitle {
        font-size: 12px;
        letter-spacing: 0.2em;
        text-transform: uppercase;
        margin-bottom: 24px;
    }
    .hero-title {
        font-size: 64px;
        font-weight: 400;
        letter-spacing: 0.05em;
        margin-bottom: 48px;
        line-height: 1.1;
        text-transform: uppercase;
    }
    .btn-primary {
        background: #ffffff;
        color: #111111;
        border: none;
        padding: 18px 48px;
        font-size: 13px;
        letter-spacing: 0.15em;
        text-transform: uppercase;
        cursor: pointer;
        font-weight: 500;
        display: inline-block;
    }
    .btn-primary.inverse {
        background: var(--primary);
        color: var(--primary-foreground);
    }
</style>

<style id="section-styles">
    .section {
        padding: 120px 60px;
    }
    .section-header {
        display: flex;
        justify-content: space-between;
        align-items: flex-end;
        margin-bottom: 60px;
    }
    .section-title {
        font-size: 28px;
        letter-spacing: 0.05em;
        text-transform: uppercase;
    }
    .section-link {
        font-size: 13px;
        text-transform: uppercase;
        letter-spacing: 0.1em;
        text-decoration: underline;
        text-underline-offset: 4px;
        cursor: pointer;
    }
</style>

<style id="product-styles">
    .product-grid {
        display: grid;
        grid-template-columns: repeat(4, 1fr);
        gap: 40px;
    }
    .product-card {
        display: flex;
        flex-direction: column;
        cursor: pointer;
    }
    .product-image {
        width: 100%;
        aspect-ratio: 3/4;
        background: var(--muted);
        margin-bottom: 24px;
        overflow: hidden;
    }
    .product-image img {
        width: 100%;
        height: 100%;
        object-fit: cover;
    }
    .product-info {
        display: flex;
        flex-direction: column;
        align-items: center;
        text-align: center;
        gap: 10px;
    }
    .product-name {
        font-size: 14px;
        letter-spacing: 0.05em;
        text-transform: uppercase;
    }
    .product-price {
        font-size: 14px;
        color: var(--muted-foreground);
    }
</style>

<style id="editorial-styles">
    .editorial {
        display: flex;
        align-items: stretch;
        min-height: 700px;
    }
    .editorial-image-col {
        flex: 1;
        position: relative;
    }
    .editorial-image-col img {
        position: absolute;
        top: 0; left: 0; width: 100%; height: 100%;
        object-fit: cover;
    }
    .editorial-content-col {
        flex: 1;
        display: flex;
        flex-direction: column;
        justify-content: center;
        align-items: center;
        text-align: center;
        padding: 80px 12%;
        background: var(--muted);
    }
    .editorial-subtitle {
        font-size: 12px;
        letter-spacing: 0.2em;
        text-transform: uppercase;
        margin-bottom: 24px;
        color: var(--muted-foreground);
    }
    .editorial-title {
        font-size: 36px;
        letter-spacing: 0.05em;
        text-transform: uppercase;
        margin-bottom: 32px;
        line-height: 1.2;
    }
    .editorial-text {
        font-size: 15px;
        line-height: 1.8;
        color: var(--muted-foreground);
        margin-bottom: 48px;
    }
</style>

<style id="collections-styles">
    .collection-row {
        display: grid;
        grid-template-columns: repeat(3, 1fr);
        gap: 40px;
        padding: 0 60px;
        margin-bottom: 120px;
    }
    .collection-card {
        position: relative;
        aspect-ratio: 4/5;
        cursor: pointer;
        overflow: hidden;
    }
    .collection-card img {
        width: 100%;
        height: 100%;
        object-fit: cover;
    }
    .collection-overlay {
        position: absolute;
        bottom: 0; left: 0; right: 0;
        padding: 40px;
        display: flex;
        flex-direction: column;
        align-items: center;
        color: #ffffff;
        z-index: 2;
    }
    .collection-gradient {
        position: absolute;
        bottom: 0; left: 0; right: 0; height: 50%;
        background: linear-gradient(to top, rgba(0,0,0,0.5), transparent);
        z-index: 1;
    }
    .collection-title {
        font-size: 24px;
        letter-spacing: 0.1em;
        text-transform: uppercase;
        margin-bottom: 16px;
    }
    .btn-link {
        font-size: 12px;
        letter-spacing: 0.15em;
        text-transform: uppercase;
        text-decoration: underline;
        text-underline-offset: 6px;
    }
</style>

<style id="press-styles">
    .press-bar {
        display: flex;
        justify-content: center;
        align-items: center;
        gap: 100px;
        padding: 80px 60px;
        border-top: 1px solid var(--border);
        border-bottom: 1px solid var(--border);
        opacity: 0.6;
    }
    .press-logo {
        font-size: 20px;
        font-weight: 600;
        letter-spacing: 0.2em;
        text-transform: uppercase;
    }
</style>

<style id="footer-styles">
    .footer {
        padding: 100px 60px;
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 48px;
    }
    .footer-links {
        display: flex;
        gap: 40px;
    }
    .footer-link {
        font-size: 12px;
        letter-spacing: 0.1em;
        text-transform: uppercase;
        color: var(--muted-foreground);
        cursor: pointer;
    }
    .footer-bottom {
        font-size: 11px;
        color: var(--muted-foreground);
        letter-spacing: 0.05em;
        text-transform: uppercase;
    }
</style>

</head><body><div class="prestige-theme">
    <div class="announcement">
        <span>Complimentary worldwide shipping on orders over $250</span>
    </div>

    <header class="header">
        <nav class="header-nav">
            <span class="header-link" data-media-type="banani-button">Shop</span>
            <span class="header-link" data-media-type="banani-button">Collections</span>
            <span class="header-link" data-media-type="banani-button">Journal</span>
        </nav>
        <div class="header-center" data-media-type="banani-button" style="cursor: pointer;">
            <img src="https://firebasestorage.googleapis.com/v0/b/banani-prod.appspot.com/o/reference-images%2F132a4cd9-3505-461f-804d-bb71af60e910?alt=media&amp;token=3173909b-532c-40b9-8c21-fe3c7e7a01c0" alt="#i❤️jamrock" style="height: 36px;">
        </div>
        <div class="header-nav right">
            <div class="header-icon" data-media-type="banani-button">
                <iconify-icon icon="lucide:search" style="font-size: 20px; color: var(--primary)"></iconify-icon>
            </div>
            <div class="header-icon" data-media-type="banani-button">
                <iconify-icon icon="lucide:user" style="font-size: 20px; color: var(--primary)"></iconify-icon>
            </div>
            <div style="display: flex; align-items: center; gap: 8px; cursor: pointer;" data-media-type="banani-button">
                <div class="header-icon">
                    <iconify-icon icon="lucide:shopping-bag" style="font-size: 20px; color: var(--primary)"></iconify-icon>
                </div>
                <span style="font-size: 13px; font-weight: 500;">0</span>
            </div>
        </div>
    </header>

    <section class="hero">
        <div class="hero-bg">
            <img data-aspect-ratio="16:9" data-query="luxury streetwear fashion lookbook model high end, natural lighting, cinematic" alt="Campaign" src="https://storage.googleapis.com/banani-generated-images/generated-images/54ddeea0-7685-47b3-9169-d7c41f3a4426.jpg">
        </div>
        <div class="hero-overlay"></div>
        <div class="hero-content">
            <p class="hero-subtitle">The New Standard</p>
            <h1 class="hero-title">Elevated<br>Essentials</h1>
            <button class="btn-primary" data-media-type="banani-button">Discover Collection</button>
        </div>
    </section>

    <section class="press-bar">
        <span class="press-logo">Vogue</span>
        <span class="press-logo">GQ</span>
        <span class="press-logo">Highsnobiety</span>
        <span class="press-logo">Hypebeast</span>
        <span class="press-logo">Complex</span>
    </section>

    <section class="section">
        <div class="section-header">
            <h2 class="section-title">Latest Arrivals</h2>
            <span class="section-link" data-media-type="banani-button">View All Products</span>
        </div>
        <div class="product-grid">
            <div class="product-card" data-media-type="banani-button">
                <div class="product-image">
                    <img data-aspect-ratio="3:4" data-query="luxury minimalist black t-shirt product shot on light gray background, streetwear" alt="Tee" src="https://storage.googleapis.com/banani-generated-images/generated-images/0e263254-c5b0-46f8-8634-b3af3932831d.jpg">
                </div>
                <div class="product-info">
                    <span class="product-name">Jamrock Signature Heavyweight Tee</span>
                    <span class="product-price">$85</span>
                </div>
            </div>
            <div class="product-card" data-media-type="banani-button">
                <div class="product-image">
                    <img data-aspect-ratio="3:4" data-query="luxury minimalist printed resort shirt product shot on light gray background, streetwear" alt="Shirt" src="https://storage.googleapis.com/banani-generated-images/generated-images/6cb0a012-dbe3-4c95-817f-236d53ba12dc.jpg">
                </div>
                <div class="product-info">
                    <span class="product-name">Kingston Resort Shirt</span>
                    <span class="product-price">$145</span>
                </div>
            </div>
            <div class="product-card" data-media-type="banani-button">
                <div class="product-image">
                    <img data-aspect-ratio="3:4" data-query="luxury minimalist cargo pants product shot on light gray background, streetwear" alt="Pants" src="https://storage.googleapis.com/banani-generated-images/generated-images/0392f2de-79d2-49a1-b1b6-cc5806d8364f.jpg">
                </div>
                <div class="product-info">
                    <span class="product-name">Ocho Rios Cargo Pants</span>
                    <span class="product-price">$180</span>
                </div>
            </div>
            <div class="product-card" data-media-type="banani-button">
                <div class="product-image">
                    <img data-aspect-ratio="3:4" data-query="luxury minimalist linen blazer product shot on light gray background, streetwear" alt="Blazer" src="https://storage.googleapis.com/banani-generated-images/generated-images/ed1f0401-1193-4513-b093-848f77b1a207.jpg">
                </div>
                <div class="product-info">
                    <span class="product-name">Montego Bay Linen Blazer</span>
                    <span class="product-price">$250</span>
                </div>
            </div>
        </div>
    </section>

    <section class="editorial">
        <div class="editorial-image-col">
            <img data-aspect-ratio="3:4" data-query="fashion editorial shot, luxury streetwear model in jamaica, high end photography" alt="Editorial" src="https://storage.googleapis.com/banani-generated-images/generated-images/baf65b69-fc41-4e8b-9585-f8ddb065ca3f.jpg">
        </div>
        <div class="editorial-content-col">
            <span class="editorial-subtitle">Our Philosophy</span>
            <h2 class="editorial-title">Uncompromising<br>Quality</h2>
            <p class="editorial-text">Every piece is crafted with meticulous attention to detail, using the finest materials sourced globally. We believe in creating garments that stand the test of time, both in durability and design.</p>
            <button class="btn-primary inverse" data-media-type="banani-button">Read Our Story</button>
        </div>
    </section>

    <section class="section">
        <div class="section-header" style="justify-content: center;">
            <h2 class="section-title">Shop By Category</h2>
        </div>
    </section>

    <div class="collection-row">
        <div class="collection-card" data-media-type="banani-button">
            <img data-aspect-ratio="4:5" data-query="men fashion streetwear model high end" alt="Mens" src="https://storage.googleapis.com/banani-generated-images/generated-images/02e70f4e-e3b7-4bb7-8e00-f8f386c081e5.jpg">
            <div class="collection-gradient"></div>
            <div class="collection-overlay">
                <h3 class="collection-title">Mens</h3>
                <span class="btn-link">Shop Now</span>
            </div>
        </div>
        <div class="collection-card" data-media-type="banani-button">
            <img data-aspect-ratio="4:5" data-query="women fashion streetwear model high end" alt="Womens" src="https://storage.googleapis.com/banani-generated-images/generated-images/16a6d63b-2ae6-4225-9c7d-7698636315b5.jpg">
            <div class="collection-gradient"></div>
            <div class="collection-overlay">
                <h3 class="collection-title">Womens</h3>
                <span class="btn-link">Shop Now</span>
            </div>
        </div>
        <div class="collection-card" data-media-type="banani-button">
            <img data-aspect-ratio="4:5" data-query="luxury streetwear bucket hat caps flatlay" alt="Headwear" src="https://storage.googleapis.com/banani-generated-images/generated-images/940adda8-703f-4c91-8c40-5e3b507d8d69.jpg">
            <div class="collection-gradient"></div>
            <div class="collection-overlay">
                <h3 class="collection-title">Headwear</h3>
                <span class="btn-link">Shop Now</span>
            </div>
        </div>
    </div>

    <footer class="footer">
        <img src="https://firebasestorage.googleapis.com/v0/b/banani-prod.appspot.com/o/reference-images%2F132a4cd9-3505-461f-804d-bb71af60e910?alt=media&amp;token=3173909b-532c-40b9-8c21-fe3c7e7a01c0" alt="#i❤️jamrock" style="height: 28px;">
        <div class="footer-links">
            <span class="footer-link" data-media-type="banani-button">FAQ</span>
            <span class="footer-link" data-media-type="banani-button">Shipping &amp; Returns</span>
            <span class="footer-link" data-media-type="banani-button">Terms of Service</span>
            <span class="footer-link" data-media-type="banani-button">Privacy Policy</span>
        </div>
        <div class="footer-bottom">
            © 2025 #i❤️jamrock
        </div>
    </footer>
</div></body>",
      "theme": null,
      "genType": "web-html-css"
    }
  ]
}
